cd /app/data/auto-opt/utils/llvm-157315 && cat <<'CODEEOF' | python $AGENT_TOOLS_DIR/apply_code.py write llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp 5643 5688
  // Handle clamp pattern: icmp eq/ne (smin (smax X, Lo), Hi), X
  // or icmp eq/ne (smax (smin X, Hi), Lo), X
  if (Pred == ICmpInst::ICMP_EQ || Pred == ICmpInst::ICMP_NE) {
    Value *InnerX = nullptr;
    const APInt *Lo = nullptr, *Hi = nullptr;
    bool IsSigned = MinMax->isSigned();
    if (IsSigned && MinMax->getIntrinsicID() == Intrinsic::smin &&
        match(MinMax->getLHS(), m_Intrinsic<Intrinsic::smax>(m_Value(InnerX), m_APInt(Lo))) &&
        match(MinMax->getRHS(), m_APInt(Hi)) && InnerX == Z) {
      // smin(smax(X, Lo), Hi) == X  -->  Lo <= X <= Hi
    } else if (IsSigned && MinMax->getIntrinsicID() == Intrinsic::smax &&
               match(MinMax->getLHS(), m_Intrinsic<Intrinsic::smin>(m_Value(InnerX), m_APInt(Hi))) &&
               match(MinMax->getRHS(), m_APInt(Lo)) && InnerX == Z) {
      // smax(smin(X, Hi), Lo) == X  -->  Lo <= X <= Hi (same)
      std::swap(Lo, Hi);
    } else if (IsSigned && MinMax->getIntrinsicID() == Intrinsic::smin &&
               match(MinMax->getRHS(), m_Intrinsic<Intrinsic::smax>(m_Value(InnerX), m_APInt(Lo))) &&
               match(MinMax->getLHS(), m_APInt(Hi)) && InnerX == Z) {
      // inner on RHS
    } else if (IsSigned && MinMax->getIntrinsicID() == Intrinsic::smax &&
               match(MinMax->getRHS(), m_Intrinsic<Intrinsic::smin>(m_Value(InnerX), m_APInt(Hi))) &&
               match(MinMax->getLHS(), m_APInt(Lo)) && InnerX == Z) {
      std::swap(Lo, Hi);
    }
    if (InnerX) {
      // Lo and Hi are the signed constants.
      // Ensure Lo <= Hi, otherwise clamp is empty (always false for equality).
      if (Lo->sle(*Hi)) {
        // Compute Delta = Hi - Lo + 1
        APInt Delta = *Hi - *Lo;
        Delta += 1;
        // Generate (X - Lo) u< Delta
        ConstantInt *NegLo = ConstantInt::get(InnerX->getType(), -(*Lo));
        Value *Offset = SimplifyAddInst(InnerX, NegLo, /*HasNUW*/ false,
                                        /*HasNSW*/ false, Q);
        if (!Offset)
          Offset = Builder.CreateAdd(InnerX, NegLo);
        ICmpInst::Predicate NewPred = (Pred == ICmpInst::ICMP_EQ) ? ICmpInst::ICMP_ULT : ICmpInst::ICMP_UGE;
        return new ICmpInst(NewPred, Offset, ConstantInt::get(InnerX->getType(), Delta));
      } else {
        // Lo > Hi, clamp cannot equal X unless X == Lo or X == Hi (handled elsewhere).
        // For equality, result is false unless X == Lo or X == Hi.
        // For simplicity, return false for eq, true for ne.
        return replaceInstUsesWith(I, ConstantInt::getBool(I.getType(), Pred == ICmpInst::ICMP_NE));
      }
    }
  }
